) VALUES
  ('Duco van Breemen', 'Chief Executive Officer', 'Helping companies expand into Australia with proven GTM and sales systems | 1,000+ founders supported · I help startups and SMEs grow their business.That might mean entering a new market, building a stronger sales system, or turning scattered leads into a repeatable pipeline.At Haymarket HQ, I’ve worked with more than 1,000 companies expanding into and across APAC. We’re the partner of the Singapore Government for their tech companies entering Australia, and we’ve supported organisations like Alibaba, Australia Post, and Tech Central to help more founders and teams grow across the region.I’ve seen', 'Greater Sydney Area', 'Senior operator with extensive ANZ market experience.', ARRAY['Trade & Government', 'Cross-border'], 'https://linkedin.com/in/ducovanbreemen', NULL, NULL, 'Haymarket HQ', FALSE, '[{"name": "Haymarket HQ"}, {"name": "Stoov"}]'::jsonb, 'uk', ARRAY['uk', 'australia'], NULL, 'duco-van-breemen', 'Trade & Government', ARRAY['international_entrant'], TRUE, TRUE),
  ('Kelsey Hill', 'Assistant Program Director, Accessing New Markets Initiative (ANMI) - Americas & EMEA', 'Supporting Australian exporters to diversify and grow in the Americas & EMEA International Trade & Investment · I’m a trade and investment professional currently supporting Australian exporters to diversify and grow in new export markets under the Australian Government''s A$50 million Accessing New Markets Initiative (ANMI).As ANMI Assistant Program Director - Americas & EMEA, I collaborate with Austrade''s Business Development teams, government and industry partners, and bilateral associations to help Australian businesses grow their global footprint and export sales. My career spans Australia, the UK, Ger', 'Melbourne, Victoria, Australia', 'Senior operator with extensive ANZ market experience.', ARRAY['Trade & Government', 'Cross-border'], 'https://linkedin.com/in/kelseyhill1', NULL, NULL, 'Australian Trade and Investment Commission (Austrade)', FALSE, '[{"name": "Australian Trade and Investment Commission (Austrade)"}, {"name": "Self employed"}]'::jsonb, 'germany', ARRAY['germany', 'australia'], NULL, 'kelsey-hill', 'Trade & Government', ARRAY['international_entrant'], TRUE, TRUE),
